// Extract RUBE payload
const payload = $input.first().json.body || $input.first().json;

const platform = (payload.platform || 'all').toLowerCase();
const content = payload.content || '';
const mediaBase64 = payload.media_base64 || '';
const mediaUrl = payload.media_url || '';
const mediaFilename = payload.media_filename || 'rube_graphic.jpg';
const mediaPath = payload.media_path || '';

// Determine if we have media
const hasMedia = !!(mediaBase64 || mediaUrl);

// If base64 exists, convert to binary buffer
let binaryData = null;
if (mediaBase64) {
  binaryData = Buffer.from(mediaBase64, 'base64');
}

const output = {
  platform,
  content,
  hasMedia,
  mediaUrl,
  mediaFilename,
  mediaPath,
  mediaBase64Length: mediaBase64.length
};

// Attach binary if available
if (binaryData) {
  const items = [{
    json: output,
    binary: {
      image: {
        data: mediaBase64,
        mimeType: 'image/jpeg',
        fileName: mediaFilename
      }
    }
  }];
  return items;
}

return [{ json: output }];

// 'All' platform: fan out to Instagram, Twitter, and Discord
// This node passes the data through unchanged.
// Connect its outputs to all three platform nodes.
return $input.all();

// If no media_url but base64 exists, upload to imgbb for a public URL
// This is needed because Instagram Graph API requires a PUBLIC image URL

const input = $input.first().json;

// If we already have a media_url (from Pollinations), pass through
if (input.mediaUrl) {
  return [{ json: input }];
}

// If we have base64 but no URL, upload to imgbb (free image host)
// You need an IMGBB_API_KEY env var — get one free at https://api.imgbb.com/
const imgbbKey = $env.IMGBB_API_KEY;
if (input.mediaBase64Length > 0 && imgbbKey) {
  const binary = $input.first().binary;
  if (binary && binary.image) {
    try {
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.imgbb.com/1/upload',
        body: {
          key: imgbbKey,
          image: binary.image.data
        },
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
      });
      input.mediaUrl = response.data.url;
      return [{ json: input }];
    } catch (e) {
      // Fall through without image
    }
  }
}

// No image available — post text only
return [{ json: input }];
